from flask import Flask, jsonify
from pymemcache.client import base
import pymysql

app = Flask(__name__)

# Configure Memcached client
memcached_client = base.Client(('localhost', 11211))

# Configure database connection
db_config = {
    'host': 'localhost',
    'user': 'your_user',
    'password': 'your_password',
    'database': 'your_database'
}

def get_db_connection():
    return pymysql.connect(**db_config)

def cache_data(key, data, ttl):
    memcached_client.set(key, data, expire=ttl)

def get_cached_data(key):
    return memcached_client.get(key)

@app.route('/api/data')
def get_data():
    cache_key = 'api_data'
    cached_data = get_cached_data(cache_key)
    
    if cached_data:
        return jsonify(cached_data)

    connection = get_db_connection()
    cursor = connection.cursor()
    cursor.execute("SELECT * FROM your_table")
    data = cursor.fetchall()
    cursor.close()
    connection.close()

    cache_data(cache_key, data, ttl=300)  # Cache for 5 minutes
    return jsonify(data)

